const puppeteer = require('puppeteer');
const fs = require('fs');
const path = require('path');

(async () => {
  const browser = await puppeteer.launch({
    headless: 'new',
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });

  const page = await browser.newPage();
  await page.goto('https://news.ycombinator.com', { waitUntil: 'networkidle2' });

  // Extract the top 5 story titles
  const titles = await page.evaluate(() => {
    const storyLinks = document.querySelectorAll('.titleline > a');
    const topFive = [];
    for (let i = 0; i < Math.min(5, storyLinks.length); i++) {
      topFive.push(storyLinks[i].textContent.trim());
    }
    return topFive;
  });

  await browser.close();

  // Format and save the titles
  const formatted = titles.map((title, index) => `${index + 1}. ${title}`).join('\n');
  const outputPath = path.join(__dirname, 'scraped_data', 'hn_titles.txt');
  fs.writeFileSync(outputPath, formatted, 'utf8');

  console.log('Scraping completed successfully!');
  console.log('Extracted titles:');
  titles.forEach((title, index) => console.log(`${index + 1}. ${title}`));
})();
EOF

